  1	import * as React from 'react';
  2	import { RateTableGrpc, RateTableHttp } from '../../components/SummaryPanel/RateTable';
  3	import { RequestChart, StreamChart } from '../../components/SummaryPanel/RpsChart';
  4	import { ResponseTimeChart, ResponseTimeUnit } from '../../components/SummaryPanel/ResponseTimeChart';
  5	import {
  6	  DecoratedGraphEdgeData,
  7	  DecoratedGraphNodeData,
  8	  GraphType,
  9	  NodeType,
 10	  prettyProtocol,
 11	  Protocol,
 12	  SummaryPanelPropType,
 13	  TrafficRate,
 14	  UNKNOWN
 15	} from '../../types/Graph';
 16	import { renderBadgedLink } from './SummaryLink';
 17	import {
 18	  getDatapoints,
 19	  getNodeMetrics,
 20	  getNodeMetricType,
 21	  getTitle,
 22	  hr,
 23	  NodeMetricType,
 24	  renderNoTraffic,
 25	  shouldRefreshData,
 26	  summaryBodyTabs,
 27	  summaryFont,
 28	  summaryPanel
 29	} from './SummaryPanelCommon';
 30	import { Datapoint, IstioMetricsMap, Labels, Metric } from '../../types/Metrics';
 31	import { CancelablePromise, makeCancelablePromise } from '../../utils/CancelablePromises';
 32	import { ResponseFlagsTable } from 'components/SummaryPanel/ResponseFlagsTable';
 33	import { ResponseHostsTable } from 'components/SummaryPanel/ResponseHostsTable';
 34	import { KialiIcon } from 'config/KialiIcon';
 35	import { Tab, Tooltip } from '@patternfly/react-core';
 36	import { SimpleTabs } from 'components/Tab/SimpleTabs';
 37	import { Direction } from 'types/MetricsOptions';
 38	import { kialiStyle } from 'styles/StyleUtils';
 39	import { Edge } from '@patternfly/react-topology';
 40	import { classes } from 'typestyle';
 41	import { panelBodyStyle, panelHeadingStyle, panelStyle } from './SummaryPanelStyle';
 42	import { ApiResponse } from 'types/Api';
 43	import { icons, serverConfig } from 'config';
 44	
 45	type SummaryPanelEdgeMetricsState = {
 46	  errRates: Datapoint[];
 47	  rates: Datapoint[];
 48	  received: Datapoint[];
 49	  rt95: Datapoint[];
 50	  rt99: Datapoint[];
 51	  rtAvg: Datapoint[];
 52	  rtMed: Datapoint[];
 53	  sent: Datapoint[];
 54	  unit: ResponseTimeUnit;
 55	  waypointReverseReceived?: Datapoint[];
 56	  waypointReverseSent?: Datapoint[];
 57	};
 58	
 59	type SummaryPanelEdgeState = SummaryPanelEdgeMetricsState & {
 60	  activePanel: PanelType;
 61	  edge: any;
 62	  loading: boolean;
 63	  metricsLoadError: string | null;
 64	};
 65	
 66	const defaultMetricsState: SummaryPanelEdgeMetricsState = {
 67	  errRates: [],
 68	  rates: [],
 69	  received: [],
 70	  rt95: [],
 71	  rt99: [],
 72	  rtAvg: [],
 73	  rtMed: [],
 74	  sent: [],
 75	  unit: 'ms'
 76	};
 77	
 78	enum PanelType {
 79	  Main = 'main',
 80	  WaypointReverse = 'waypointReverse'
 81	}
 82	
 83	const defaultState: SummaryPanelEdgeState = {
 84	  edge: null,
 85	  loading: false,
 86	  metricsLoadError: null,
 87	  activePanel: PanelType.Main,
 88	  ...defaultMetricsState
 89	};
 90	
 91	const principalStyle = kialiStyle({
 92	  display: 'inline-block',
 93	  overflow: 'hidden',
 94	  textOverflow: 'ellipsis',
 95	  width: '100%',
 96	  whiteSpace: 'nowrap'
 97	});
 98	
 99	const switchWaypointIcon = kialiStyle({
100	  marginTop: '-3em'
101	});
102	
103	const fromToStyle = kialiStyle({
104	  marginLeft: '2em'
105	});
106	
107	export class SummaryPanelEdge extends React.Component<SummaryPanelPropType, SummaryPanelEdgeState> {
108	  private metricsPromise?: CancelablePromise<ApiResponse<IstioMetricsMap>>;
109	  private readonly mainDivRef: React.RefObject<HTMLDivElement>;
110	
111	  constructor(props: SummaryPanelPropType) {
112	    super(props);
113	
114	    this.state = { ...defaultState };
115	    this.mainDivRef = React.createRef<HTMLDivElement>();
116	  }
117	
118	  static getDerivedStateFromProps(
119	    props: SummaryPanelPropType,
120	    state: SummaryPanelEdgeState
121	  ): Partial<SummaryPanelEdgeState> | null {
122	    // if the summaryTarget (i.e. selected edge) has changed, then init the state and set to loading. The loading
123	    // will actually be kicked off after the render (in componentDidMount/Update).
124	    return props.data.summaryTarget !== state.edge
125	      ? { edge: props.data.summaryTarget, loading: true, ...defaultMetricsState }
126	      : null;
127	  }
128	
129	  componentDidMount(): void {
130	    this.updateCharts(this.props);
131	  }
132	
133	  componentDidUpdate(prevProps: SummaryPanelPropType): void {
134	    if (prevProps.data.summaryTarget !== this.props.data.summaryTarget) {
135	      if (this.mainDivRef.current) {
136	        this.mainDivRef.current.scrollTop = 0;
137	      }
138	    }
139	
140	    if (shouldRefreshData(prevProps, this.props)) {
141	      this.updateCharts(this.props);
142	    }
143	  }
144	
145	  componentWillUnmount(): void {
146	    if (this.metricsPromise) {
147	      this.metricsPromise.cancel();
148	    }
149	  }
150	
151	  updateTab = (e: React.MouseEvent<HTMLAnchorElement>): void => {
152	    e.preventDefault();
153	    if (this.state.activePanel === PanelType.Main) {
154	      this.setState({ activePanel: PanelType.WaypointReverse });
155	    } else {
156	      this.setState({ activePanel: PanelType.Main });
157	    }
158	  };
159	
160	  render(): React.ReactNode {
161	    const edge = this.props.data.summaryTarget;
162	    const edgeData = (edge as Edge).getData() as DecoratedGraphEdgeData;
163	    const sourceData = (edge as Edge).getSource().getData() as DecoratedGraphNodeData;
164	    const destData = (edge as Edge).getTarget().getData() as DecoratedGraphNodeData;
165	    const mTLSPercentage = edgeData.isMTLS;
166	    const isMtls = mTLSPercentage && mTLSPercentage > 0;
167	    const hasPrincipals = !!edgeData.sourcePrincipal || !!edgeData.destPrincipal;
168	    const hasSecurity = isMtls || hasPrincipals;
169	    const protocol = edgeData.protocol;
170	    const isGrpc = protocol === Protocol.GRPC;
171	    const isHttp = protocol === Protocol.HTTP;
172	    const isTcp = protocol === Protocol.TCP;
173	    const isRequests = isHttp || (isGrpc && this.props.trafficRates.includes(TrafficRate.GRPC_REQUEST));
174	
175	    const SecurityBlock = (): React.ReactElement => {
176	      return (
177	        <div className={panelHeadingStyle}>
178	          {isMtls && this.renderMTLSSummary(mTLSPercentage)}
179	          {hasPrincipals && (
180	            <>
181	              <div style={{ padding: '0.25rem 0 0.125rem 0' }}>
182	                <strong>Principals:</strong>
183	              </div>
184	
185	              <Tooltip key="tt_src_ppl" position="top" content={`Source principal: ${edgeData.sourcePrincipal}`}>
186	                <span className={principalStyle}>{edgeData.sourcePrincipal ?? 'unknown'}</span>
187	              </Tooltip>
188	
189	              <Tooltip key="tt_src_ppl" position="top" content={`Destination principal: ${edgeData.destPrincipal}`}>
190	                <span className={principalStyle}>{edgeData.destPrincipal ?? 'unknown'}</span>
191	              </Tooltip>
192	            </>
193	          )}
194	        </div>
195	      );
196	    };
197	
198	    const MainSummary = (): React.ReactElement => {
199	      const isWaypointEdge = !!edgeData.waypoint;
200	      const isBidirectional = isWaypointEdge && !!edgeData.waypoint?.fromEdge;
201	      const isReversed = isBidirectional && this.state.activePanel === PanelType.WaypointReverse;
202	      const source = isReversed ? destData : sourceData;
203	      const dest = isReversed ? sourceData : destData;
204	      return (
205	        <div>
206	          <div className={panelHeadingStyle}>
207	            {getTitle(`Edge (${prettyProtocol(protocol)})`)}
208	            {renderBadgedLink(source, undefined, 'From:  ', undefined, isBidirectional ? fromToStyle : undefined)}
209	            {renderBadgedLink(
210	              dest,
211	              undefined,
212	              'To:        ',
213	              undefined,
214	              isBidirectional ? fromToStyle : undefined
215	            )}{' '}
216	            {isBidirectional && (
217	              <div className={switchWaypointIcon}>
218	                <Tooltip key="waypoint" position="top" content="Switch From/To">
219	                  <a
220	                    href="#"
221	                    onClick={this.updateTab}
222	                    style={{ textDecoration: 'none', cursor: 'pointer', fontSize: '1.5em' }}
223	                  >
224	                    {this.state.activePanel === 'main'
225	                      ? icons.unicode.arrowDownLeftofUp.char
226	                      : icons.unicode.arrowUpLeftofDown.char}
227	                  </a>
228	                </Tooltip>
229	              </div>
230	            )}
231	          </div>
232	
233	          {hasSecurity && <SecurityBlock />}
234	
235	          {(isHttp || isGrpc) && (
236	            <div className={summaryBodyTabs}>
237	              <SimpleTabs id="edge_summary_rate_tabs" defaultTab={0} style={{ paddingBottom: '0.5rem' }}>
238	                <Tab style={summaryFont} title="Traffic" eventKey={0}>
239	                  <div style={summaryFont}>
240	                    {isGrpc && (
241	                      <>
242	                        <RateTableGrpc
243	                          isRequests={isRequests}
244	                          rate={this.safeRate(edgeData.grpc)}
245	                          rateGrpcErr={this.safeRate(edgeData.grpcErr)}
246	                          rateNR={this.safeRate(edgeData.grpcNoResponse)}
247	                        />
248	                      </>
249	                    )}
250	
251	                    {isHttp && (
252	                      <>
253	                        <RateTableHttp
254	                          title="HTTP requests per second:"
255	                          rate={this.safeRate(edgeData.http)}
256	                          rate3xx={this.safeRate(edgeData.http3xx)}
257	                          rate4xx={this.safeRate(edgeData.http4xx)}
258	                          rate5xx={this.safeRate(edgeData.http5xx)}
259	                          rateNR={this.safeRate(edgeData.httpNoResponse)}
260	                        />
261	                      </>
262	                    )}
263	                  </div>
264	                </Tab>
265	
266	                {isRequests && (
267	                  <Tab style={summaryFont} title="Flags" eventKey={1}>
268	                    <div style={summaryFont}>
269	                      <ResponseFlagsTable
270	                        title={`Response flags by ${isGrpc ? 'GRPC code:' : 'HTTP code:'}`}
271	                        responses={edgeData.responses}
272	                      />
273	                    </div>
274	                  </Tab>
275	                )}
276	                <Tab style={summaryFont} title="Hosts" eventKey={2}>
277	                  <div style={summaryFont}>
278	                    <ResponseHostsTable
279	                      title={`Hosts by ${isGrpc ? 'GRPC code:' : 'HTTP code:'}`}
280	                      responses={edgeData.responses}
281	                    />
282	                  </div>
283	                </Tab>
284	              </SimpleTabs>
285	              {hr()}
286	              {this.renderCharts(edge, isGrpc, isHttp, isTcp, isRequests)}
287	            </div>
288	          )}
289	
290	          {isTcp && (
291	            <div className={summaryBodyTabs}>
292	              <SimpleTabs id="edge_summary_flag_hosts_tabs" defaultTab={0} style={{ paddingBottom: '0.5rem' }}>
293	                <Tab style={summaryFont} eventKey={0} title="Flags">
294	                  <div style={summaryFont}>
295	                    <ResponseFlagsTable
296	                      title="Response flags by code:"
297	                      responses={isReversed ? edgeData.waypoint!.fromEdge!.responses : edgeData.responses}
298	                    />
299	                  </div>
300	                </Tab>
301	
302	                <Tab style={summaryFont} eventKey={1} title="Hosts">
303	                  <div style={summaryFont}>
304	                    <ResponseHostsTable
305	                      title="Hosts by code:"
306	                      responses={isReversed ? edgeData.waypoint!.fromEdge!.responses : edgeData.responses}
307	                    />
308	                  </div>
309	                </Tab>
310	              </SimpleTabs>
311	
312	              {hr()}
313	
314	              {this.renderCharts(edge, isGrpc, isHttp, isTcp, isRequests, isReversed)}
315	            </div>
316	          )}
317	
318	          {!isGrpc && !isHttp && !isTcp && <div className={panelBodyStyle}>{renderNoTraffic()}</div>}
319	        </div>
320	      );
321	    };
322	
323	    return (
324	      <div ref={this.mainDivRef} className={classes(panelStyle, summaryPanel)}>
325	        <MainSummary />
326	      </div>
327	    );
328	  }
329	
330	  private getByLabels = (sourceMetricType: NodeMetricType, destMetricType: NodeMetricType): string[] => {
331	    let label: string;
332	
333	    switch (sourceMetricType) {
334	      case NodeMetricType.AGGREGATE:
335	        switch (destMetricType) {
336	          case NodeMetricType.APP:
337	            label = 'destination_app';
338	            break;
339	          case NodeMetricType.SERVICE:
340	            label = 'destination_service_name';
341	            break;
342	          case NodeMetricType.WORKLOAD:
343	          // fall through, workload is default
344	          default:
345	            label = 'destination_workload';
346	            break;
347	        }
348	        break;
349	      case NodeMetricType.APP:
350	        label = 'source_app';
351	        break;
352	      case NodeMetricType.SERVICE:
353	        label = 'destination_service_name';
354	        break;
355	      case NodeMetricType.WORKLOAD:
356	      // fall through, workload is default
357	      default:
358	        label = 'source_workload';
359	        break;
360	    }
361	
362	    // For special service dest nodes we want to narrow the data to only TS with 'unknown' workloads (see the related
363	    // comparator in getNodeDatapoints).
364	    return this.isSpecialServiceDest(destMetricType) ? [label, 'destination_workload'] : [label];
365	  };
366	
367	  private getNodeDataPoints = (
368	    m: Metric[] | undefined,
369	    sourceMetricType: NodeMetricType,
370	    destMetricType: NodeMetricType,
371	    data: DecoratedGraphNodeData,
372	    isServiceEntry: boolean
373	  ): Datapoint[] => {
374	    if (isServiceEntry) {
375	      // For service entries, metrics are grouped by destination_service_name and we need to match it per "data.destServices"
376	      return getDatapoints(m, (labels: Labels) => {
377	        return data.destServices
378	          ? data.destServices.some(svc => svc.name === labels['destination_service_name'])
379	          : false;
380	      });
381	    }
382	
383	    let label: string;
384	    let value: string | undefined;
385	
386	    switch (sourceMetricType) {
387	      case NodeMetricType.AGGREGATE:
388	        switch (destMetricType) {
389	          case NodeMetricType.APP:
390	            label = 'destination_app';
391	            value = data.app;
392	            break;
393	          case NodeMetricType.SERVICE:
394	            label = 'destination_service_name';
395	            value = data.service;
396	            break;
397	          case NodeMetricType.WORKLOAD:
398	          // fall through, workload is default
399	          default:
400	            label = 'destination_workload';
401	            value = data.workload;
402	            break;
403	        }
404	        break;
405	      case NodeMetricType.APP:
406	        label = 'source_app';
407	        value = data.app;
408	        break;
409	      case NodeMetricType.SERVICE:
410	        label = 'destination_service_name';
411	        value = data.service;
412	        break;
413	      case NodeMetricType.WORKLOAD:
414	      // fall through, use workload as the default
415	      default:
416	        label = 'source_workload';
417	        value = data.workload;
418	    }
419	
420	    const comparator = this.isSpecialServiceDest(destMetricType)
421	      ? (labels: Labels) => labels[label] === value && labels.destination_workload === UNKNOWN
422	      : (labels: Labels) => labels[label] === value;
423	
424	    return getDatapoints(m, comparator);
425	  };
426	
427	  private updateCharts = (props: SummaryPanelPropType): void => {
428	    const edge = this.props.data.summaryTarget;
429	    const edgeData = (edge as Edge).getData() as DecoratedGraphEdgeData;
430	    const sourceData = (edge as Edge).getSource().getData() as DecoratedGraphNodeData;
431	    const destData = (edge as Edge).getTarget().getData() as DecoratedGraphNodeData;
432	    const sourceMetricType = getNodeMetricType(sourceData);
433	    const destMetricType = getNodeMetricType(destData);
434	    const protocol = edgeData.protocol;
435	    const isGrpc = protocol === Protocol.GRPC;
436	    const isHttp = protocol === Protocol.HTTP;
437	    const isTcp = protocol === Protocol.TCP;
438	    const isRequests = isHttp || (isGrpc && this.props.trafficRates.includes(TrafficRate.GRPC_REQUEST));
439	    const isWaypointEdge = !!edgeData.waypoint;
440	    const isBidirectional = isWaypointEdge && !!edgeData.waypoint?.fromEdge;
441	
442	    if (this.metricsPromise) {
443	      this.metricsPromise.cancel();
444	      this.metricsPromise = undefined;
445	    }
446	
447	    // Just return if the metric types are unset, there is no data, destination node is "unknown" or charts are unsupported
448	    if (
449	      !destMetricType ||
450	      !sourceMetricType ||
451	      !this.hasSupportedCharts(edge) ||
452	      (!isGrpc && !isHttp && !isTcp) ||
453	      destData.isInaccessible
454	    ) {
455	      this.setState({
456	        loading: false
457	      });
458	      return;
459	    }
460	
461	    // use dest node metrics unless dest is a serviceEntry or source is an aggregate
462	    const isSourceAggregate = sourceData.nodeType === NodeType.AGGREGATE;
463	    const isDestServiceEntry = !!destData.isServiceEntry;
464	    const useDestMetrics = isDestServiceEntry || isSourceAggregate ? false : true;
465	    const metricsNodeData = useDestMetrics ? destData : sourceData;
466	    const direction: Direction = useDestMetrics || isSourceAggregate ? 'inbound' : 'outbound';
467	    const metricType = useDestMetrics ? destMetricType : sourceMetricType;
468	    const byLabels = isDestServiceEntry
469	      ? ['destination_service_name']
470	      : this.getByLabels(sourceMetricType, destMetricType);
471	    const otherEndData = useDestMetrics ? sourceData : destData;
472	    const quantiles = ['0.5', '0.95', '0.99'];
473	
474	    let promiseRequests: Promise<ApiResponse<IstioMetricsMap>>;
475	
476	    if (isHttp || (isGrpc && isRequests)) {
477	      const reporterRps =
478	        [NodeType.SERVICE, NodeType.UNKNOWN].includes(sourceData.nodeType) ||
479	        NodeType.AGGREGATE === metricsNodeData.nodeType ||
480	        sourceData.isIstio
481	          ? 'destination'
482	          : 'source';
483	
484	      const filtersRps = ['request_count', 'request_duration_millis', 'request_error_count'];
485	
486	      promiseRequests = getNodeMetrics(
487	        metricType,
488	        metricsNodeData,
489	        props,
490	        filtersRps,
491	        direction,
492	        reporterRps,
493	        serverConfig.ambientEnabled, // TODO change to "metricsNodeData.isAmbient" when it is set for this node type
494	        protocol,
495	        quantiles,
496	        byLabels
497	      );
498	    } else if (isGrpc) {
499	      // gRPC messages uses slightly different reporting
500	      const reporter =
501	        [NodeType.AGGREGATE, NodeType.UNKNOWN].includes(sourceData.nodeType) || sourceData.isIstio
502	          ? 'destination'
503	          : 'source';
504	
505	      const filters = ['grpc_sent', 'grpc_received'];
506	
507	      promiseRequests = getNodeMetrics(
508	        metricType,
509	        metricsNodeData,
510	        props,
511	        filters,
512	        direction,
513	        reporter,
514	        serverConfig.ambientEnabled, // TODO change to "metricsNodeData.isAmbient" when it is set for this node type
515	        undefined, // streams (tcp, grpc-messages) use dedicated metrics (i.e. no request_protocol label)
516	        quantiles,
517	        byLabels
518	      );
519	    } else {
520	      // TCP uses slightly different reporting
521	      const reporterTCP =
522	        [NodeType.AGGREGATE, NodeType.UNKNOWN].includes(sourceData.nodeType) ||
523	        sourceData.isIstio ||
524	        (isWaypointEdge && edgeData.waypoint?.direction === 'from')
525	          ? 'destination'
526	          : 'source';
527	      const filtersTCP = ['tcp_sent', 'tcp_received'];
528	
529	      // for bidirectional edges make an additional fetch for the reverse direction's metrics
530	      if (isBidirectional) {
531	        const waypointMetricType = sourceMetricType;
532	        const waypointMetricsNodeData = sourceData;
533	        const waypointPromRequests = getNodeMetrics(
534	          waypointMetricType,
535	          waypointMetricsNodeData,
536	          props,
537	          filtersTCP,
538	          direction,
539	          'destination',
540	          undefined, // TCP metrics include ambient by default (ztunnel already uses source/dest reporting)
541	          undefined, // streams (tcp, grpc-messages) use dedicated metrics (i.e. no request_protocol label)
542	          quantiles,
543	          ['source_workload']
544	        );
545	        this.metricsPromise = makeCancelablePromise(waypointPromRequests);
546	        this.metricsPromise.promise
547	          .then(response => {
548	            const metrics = response.data;
549	
550	            const sent = this.getNodeDataPoints(
551	              metrics.tcp_sent,
552	              NodeMetricType.WORKLOAD,
553	              NodeMetricType.WORKLOAD,
554	              destData,
555	              isDestServiceEntry
556	            );
557	
558	            const received = this.getNodeDataPoints(
559	              isTcp ? metrics.tcp_received : metrics.grpc_received,
560	              NodeMetricType.WORKLOAD,
561	              NodeMetricType.WORKLOAD,
562	              destData,
563	              isDestServiceEntry
564	            );
565	
566	            this.setState({
567	              waypointReverseSent: sent,
568	              waypointReverseReceived: received
569	            });
570	          })
571	          .catch(error => {
572	            console.debug(`SummaryPanelEdge: Ignore fetch error for waypoint metrics (canceled) ${error}`);
573	          });
574	      }
575	
576	      promiseRequests = getNodeMetrics(
577	        metricType,
578	        metricsNodeData,
579	        props,
580	        filtersTCP,
581	        direction,
582	        reporterTCP,
583	        undefined, // TCP metrics include ambient by default (ztunnel already uses source/dest reporting)
584	        undefined, // streams (tcp, grpc-messages) use dedicated metrics (i.e. no request_protocol label)
585	        quantiles,
586	        byLabels
587	      );
588	    }
589	
590	    this.metricsPromise = makeCancelablePromise(promiseRequests);
591	
592	    this.metricsPromise.promise
593	      .then(response => {
594	        const metrics = response.data;
595	        let { rates: reqRates, errRates, rtAvg, rtMed, rt95, rt99, sent, received, unit } = defaultMetricsState;
596	        if (isHttp || (isGrpc && isRequests)) {
597	          reqRates = this.getNodeDataPoints(
598	            metrics.request_count,
599	            sourceMetricType,
600	            destMetricType,
601	            otherEndData,
602	            isDestServiceEntry
603	          );
604	
605	          errRates = this.getNodeDataPoints(
606	            metrics.request_error_count,
607	            sourceMetricType,
608	            destMetricType,
609	            otherEndData,
610	            isDestServiceEntry
611	          );
612	
613	          const duration = metrics.request_duration_millis ?? [];
614	
615	          rtAvg = this.getNodeDataPoints(
616	            duration.filter(m => m.stat === 'avg'),
617	            sourceMetricType,
618	            destMetricType,
619	            otherEndData,
620	            isDestServiceEntry
621	          );
622	
623	          rtMed = this.getNodeDataPoints(
624	            duration.filter(m => m.stat === '0.5'),
625	            sourceMetricType,
626	            destMetricType,
627	            otherEndData,
628	            isDestServiceEntry
629	          );
630	
631	          rt95 = this.getNodeDataPoints(
632	            duration.filter(m => m.stat === '0.95'),
633	            sourceMetricType,
634	            destMetricType,
635	            otherEndData,
636	            isDestServiceEntry
637	          );
638	
639	          rt99 = this.getNodeDataPoints(
640	            duration.filter(m => m.stat === '0.99'),
641	            sourceMetricType,
642	            destMetricType,
643	            otherEndData,
644	            isDestServiceEntry
645	          );
646	        } else {
647	          // TCP or gRPC stream
648	          sent = this.getNodeDataPoints(
649	            isTcp ? metrics.tcp_sent : metrics.grpc_sent,
650	            sourceMetricType,
651	            destMetricType,
652	            otherEndData,
653	            isDestServiceEntry
654	          );
655	
656	          received = this.getNodeDataPoints(
657	            isTcp ? metrics.tcp_received : metrics.grpc_received,
658	            sourceMetricType,
659	            destMetricType,
660	            otherEndData,
661	            isDestServiceEntry
662	          );
663	        }
664	
665	        this.setState({
666	          loading: false,
667	          rates: reqRates,
668	          errRates: errRates,
669	          rtAvg: rtAvg,
670	          rtMed: rtMed,
671	          rt95: rt95,
672	          rt99: rt99,
673	          sent: sent,
674	          received: received,
675	          unit: unit
676	        });
677	      })
678	      .catch(error => {
679	        if (error.isCanceled) {
680	          console.debug('SummaryPanelEdge: Ignore fetch error (canceled).');
681	          return;
682	        }
683	
684	        const errorMsg = error.response && error.response.data.error ? error.response.data.error : error.message;
685	        this.setState({
686	          loading: false,
687	          metricsLoadError: errorMsg,
688	          ...defaultMetricsState
689	        });
690	      });
691	
692	    this.setState({ loading: true, metricsLoadError: null });
693	  };
694	
695	  private safeRate = (s: number): number => {
696	    return isNaN(s) ? 0.0 : Number(s);
697	  };
698	
699	  private renderCharts = (
700	    edge: any,
701	    isGrpc: boolean,
702	    isHttp: boolean,
703	    isTcp: boolean,
704	    isRequests: boolean,
705	    isWaypointEdge?: boolean
706	  ): React.ReactNode => {
707	    if (!this.hasSupportedCharts(edge)) {
708	      return isGrpc || isHttp ? (
709	        <>
710	          <KialiIcon.Info /> Service graphs do not support service-to-service aggregate sparklines. See the chart above
711	          for aggregate traffic or use the workload graph type to observe individual workload-to-service edge
712	          sparklines.
713	        </>
714	      ) : (
715	        <>
716	          <KialiIcon.Info /> Service graphs do not support service-to-service aggregate sparklines. Use the workload
717	          graph type to observe individual workload-to-service edge sparklines.
718	        </>
719	      );
720	    }
721	
722	    const destData = (edge as Edge).getTarget().getData();
723	
724	    if (destData.isInaccessible) {
725	      return (
726	        <>
727	          <KialiIcon.Info /> Sparkline charts cannot be shown because the destination is inaccessible.
728	        </>
729	      );
730	    }
731	
732	    if (this.state.loading) {
733	      return <strong>Loading charts...</strong>;
734	    }
735	
736	    if (this.state.metricsLoadError) {
737	      return (
738	        <div>
739	          <KialiIcon.Warning /> <strong>Error loading metrics: </strong>
740	          {this.state.metricsLoadError}
741	        </div>
742	      );
743	    }
744	
745	    let requestChart: React.ReactNode, streamChart: React.ReactNode;
746	
747	    if (isGrpc || isHttp) {
748	      if (isRequests) {
749	        const labelRps = isGrpc ? 'gRPC Request Traffic' : 'HTTP Request Traffic';
750	        const labelRt = isGrpc ? 'gRPC Request Response Time (ms)' : 'HTTP Request Response Time (ms)';
751	
752	        requestChart = (
753	          <>
754	            <RequestChart label={labelRps} dataRps={this.state.rates!} dataErrors={this.state.errRates} />
755	            {hr()}
756	
757	            <ResponseTimeChart
758	              label={labelRt}
759	              rtAvg={this.state.rtAvg}
760	              rtMed={this.state.rtMed}
761	              rt95={this.state.rt95}
762	              rt99={this.state.rt99}
763	              unit={this.state.unit}
764	            />
765	          </>
766	        );
767	      } else {
768	        // assume gRPC messages, it's the only option other than requests
769	        requestChart = (
770	          <StreamChart
771	            label="gRPC Message Traffic"
772	            sentRates={this.state.sent!}
773	            receivedRates={this.state.received!}
774	            unit="messages"
775	          />
776	        );
777	      }
778	    } else if (isTcp) {
779	      if (isWaypointEdge && this.state.waypointReverseSent && this.state.waypointReverseReceived) {
780	        streamChart = (
781	          <StreamChart
782	            label="TCP Traffic (Waypoint)"
783	            sentRates={this.state.waypointReverseSent}
784	            receivedRates={this.state.waypointReverseReceived}
785	            unit="bytes"
786	          />
787	        );
788	      } else {
789	        streamChart = (
790	          <StreamChart
791	            label="TCP Traffic"
792	            sentRates={this.state.sent}
793	            receivedRates={this.state.received}
794	            unit="bytes"
795	          />
796	        );
797	      }
798	    }
799	
800	    return (
801	      <>
802	        {requestChart}
803	        {streamChart}
804	      </>
805	    );
806	  };
807	
808	  private hasSupportedCharts = (edge: any): boolean => {
809	    const sourceData = (edge as Edge).getSource().getData();
810	    const destData = (edge as Edge).getTarget().getData();
811	    const sourceMetricType = getNodeMetricType(sourceData);
812	    const destMetricType = getNodeMetricType(destData);
813	
814	    // service-to-service edges are unsupported because they represent aggregations (of multiple workload to service edges)
815	    const chartsSupported = sourceMetricType !== NodeMetricType.SERVICE || destMetricType !== NodeMetricType.SERVICE;
816	    return chartsSupported;
817	  };
818	
819	  // We need to handle the special case of a dest service node showing client failures. These service nodes show up in
820	  // non-service graphs, even when not injecting service nodes.
821	  private isSpecialServiceDest(destMetricType: NodeMetricType): boolean {
822	    return (
823	      destMetricType === NodeMetricType.SERVICE &&
824	      !this.props.injectServiceNodes &&
825	      this.props.graphType !== GraphType.SERVICE
826	    );
827	  }
828	
829	  private renderMTLSSummary = (mTLSPercentage: number): React.ReactNode => {
830	    let mtls = 'mTLS Enabled';
831	    const isMtls = mTLSPercentage > 0;
832	    if (isMtls && mTLSPercentage < 100.0) {
833	      mtls = `${mtls} [${mTLSPercentage}% of request traffic]`;
834	    }
835	    return (
836	      <>
837	        {isMtls && (
838	          <div>
839	            <KialiIcon.MtlsLock />
840	            <span style={{ paddingLeft: '0.375rem' }}>{mtls}</span>
841	          </div>
842	        )}
843	      </>
844	    );
845	  };
846	}

